class APMConfig:
    """APM Configuration settings."""
    
    def __init__(self):
        self.service_name = os.environ.get('APM_SERVICE_NAME', 'my-python-app')
        self.service_version = os.environ.get('APM_SERVICE_VERSION', '1.0.0')
        self.environment = os.environ.get('APM_ENVIRONMENT', 'development')
        self.server_url = os.environ.get('APM_SERVER_URL', 'http://localhost:8200')
        self.secret_token = os.environ.get('APM_SECRET_TOKEN', '')
        self.capture_body = os.environ.get('APM_CAPTURE_BODY', 'all')  # 'off', 'errors', 'all'
        self.capture_headers = os.environ.get('APM_CAPTURE_HEADERS', 'true').lower() == 'true'
        self.collect_sql_queries = os.environ.get('APM_COLLECT_SQL', 'true').lower() == 'true'
        self.stack_trace_limit = int(os.environ.get('APM_STACK_TRACE_LIMIT', '50'))
        self.transaction_sample_rate = float(os.environ.get('APM_SAMPLE_RATE', '1.0'))
        self.span_frames_min_duration = os.environ.get('APM_SPAN_FRAMES_MIN_DURATION', '5ms')
        self.enabled = os.environ.get('APM_ENABLED', 'true').lower() == 'true'


class StackTraceCapture:
    """Captures and formats stack traces for APM reporting."""
    
    @staticmethod
    def capture(limit=50):
        import traceback
        frames = traceback.extract_stack()
        # Remove the last frame (this method itself)
        frames = frames[:-1]
        if limit:
            frames = frames[-limit:]
        
        stack_trace = []
        for frame in frames:
            stack_trace.append({
                'filename': frame.filename,
                'lineno': frame.lineno,
                'name': frame.name,
                'line': frame.line or ''
            })
        return stack_trace

    @staticmethod
    def capture_exception():
        import traceback
        import sys
        exc_type, exc_value, exc_tb = sys.exc_info()
        if exc_type is None:
            return None
        
        frames = traceback.extract_tb(exc_tb)
        stack_trace = []
        for frame in frames:
            stack_trace.append({
                'filename': frame.filename,
                'lineno': frame.lineno,
                'name': frame.name,
                'line': frame.line or ''
            })
        
        return {
            'exception_type': exc_type.__name__,
            'exception_message': str(exc_value),
            'stack_trace': stack_trace
        }


class Span:
    """Represents a span within a transaction."""
    
    def __init__(self, name, span_type, subtype=None, action=None, parent=None):
        self.id = id(self)
        self.name = name
        self.type = span_type
        self.subtype = subtype
        self.action = action
        self.parent = parent
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.context = {}
        self.stack_trace = []
        self.outcome = 'success'
    
    def set_context(self, key, value):
        self.context[key] = value
    
    def end(self):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000
    
    def to_dict(self):
        return {
            'id': self.id,
            'name': self.name,
            'type': self.type,
            'subtype': self.subtype,
            'action': self.action,
            'start_time': self.start_time,
            'duration_ms': self.duration_ms,
            'context': self.context,
            'stack_trace': self.stack_trace,
            'outcome': self.outcome
        }


class Transaction:
    """Represents an APM transaction."""
    
    def __init__(self, name, transaction_type='request'):
        self.id = id(self)
        self.name = name
        self.type = transaction_type
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.result = None
        self.outcome = 'success'
        self.context = {
            'request': {},
            'response': {},
            'custom': {},
            'tags': {}
        }
        self.spans = []
        self.errors = []
        self._current_span = None
    
    def set_request_context(self, method=None, url=None, headers=None, body=None):
        self.context['request'] = {
            'method': method,
            'url': url,
            'headers': headers or {},
            'body': body,
            'timestamp': datetime.utcnow().isoformat()
        }
    
    def set_response_context(self, status_code=None, headers=None, body=None):
        self.context['response'] = {
            'status_code': status_code,
            'headers': headers or {},
            'body': body,
            'timestamp': datetime.utcnow().isoformat()
        }
    
    def set_custom_context(self, key, value):
        self.context['custom'][key] = value
    
    def set_tag(self, key, value):
        self.context['tags'][key] = value
    
    def begin_span(self, name, span_type, subtype=None, action=None):
        span = Span(name, span_type, subtype, action, parent=self._current_span)
        span.stack_trace = StackTraceCapture.capture()
        self._current_span = span
        self.spans.append(span)
        return span
    
    def end_span(self, span):
        span.end()
        if self._current_span == span:
            self._current_span = span.parent
    
    def record_error(self, error_info):
        self.errors.append(error_info)
        self.outcome = 'failure'
    
    def end(self, result=None):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000
        if result:
            self.result = result
    
    def to_dict(self):
        return {
            'id': self.id,
            'name': self.name,
            'type': self.type,
            'start_time': self.start_time,
            'duration_ms': self.duration_ms,
            'result': self.result,
            'outcome': self.outcome,
            'context': self.context,
            'spans': [s.to_dict() for s in self.spans],
            'errors': self.errors,
            'span_count': len(self.spans)
        }


class APMClient:
    """Main APM Client for instrumentation and reporting."""
    
    _instance = None
    
    def __new__(cls, config=None):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._initialized = False
        return cls._instance
    
    def __init__(self, config=None):
        if self._initialized:
            return
        
        self.config = config or APMConfig()
        self._transactions = []
        self._current_transaction = None
        self._metrics = {
            'transaction_count': 0,
            'error_count': 0,
            'span_count': 0,
            'total_duration_ms': 0
        }
        self._initialized = True
        
        if self.config.enabled:
            logger.info(
                f"APM Client initialized - Service: {self.config.service_name}, "
                f"Environment: {self.config.environment}, "
                f"Server: {self.config.server_url}"
            )
            self._try_connect_elastic_apm()
    
    def _try_connect_elastic_apm(self):
        """Try to initialize elastic-apm if available."""
        self._elastic_client = None
        try:
            import elasticapm
            self._elastic_client = elasticapm.Client(
                service_name=self.config.service_name,
                server_url=self.config.server_url,
                secret_token=self.config.secret_token,
                environment=self.config.environment,
                service_version=self.config.service_version,
                capture_body=self.config.capture_body,
                capture_headers=self.config.capture_headers,
                transaction_sample_rate=self.config.transaction_sample_rate,
                span_frames_min_duration=self.config.span_frames_min_duration,
                stack_trace_limit=self.config.stack_trace_limit,
            )
            logger.info("Elastic APM client connected successfully")
        except ImportError:
            logger.warning(
                "elastic-apm package not installed. Using built-in APM tracking. "
                "Install with: pip install elastic-apm"
            )
        except Exception as e:
            logger.warning(f"Could not connect to Elastic APM server: {e}. Using built-in tracking.")
    
    def begin_transaction(self, name, transaction_type='request'):
        if not self.config.enabled:
            return None
        
        transaction = Transaction(name, transaction_type)
        self._current_transaction = transaction
        
        if self._elastic_client:
            try:
                import elasticapm
                elasticapm.instrument()
                self._elastic_client.begin_transaction(transaction_type)
            except Exception as e:
                logger.debug(f"Elastic APM begin_transaction error: {e}")
        
        logger.info(f"Transaction started: {name} (type: {transaction_type})")
        return transaction
    
    def end_transaction(self, transaction, result=None):
        if not self.config.enabled or not transaction:
            return
        
        transaction.end(result)
        self._transactions.append(transaction)
        self._metrics['transaction_count'] += 1
        self._metrics['span_count'] += len(transaction.spans)
        self._metrics['total_duration_ms'] += transaction.duration_ms or 0
        
        if self._elastic_client:
            try:
                import elasticapm
                elasticapm.set_custom_context(transaction.context.get('custom', {}))
                for key, value in transaction.context.get('tags', {}).items():
                    elasticapm.tag(**{key: value})
                self._elastic_client.end_transaction(transaction.name, result or transaction.result)
            except Exception as e:
                logger.debug(f"Elastic APM end_transaction error: {e}")
        
        self._report_transaction(transaction)
        self._current_transaction = None
    
    @contextmanager
    def transaction(self, name, transaction_type='request'):
        txn = self.begin_transaction(name, transaction_type)
        try:
            yield txn
            self.end_transaction(txn, result='success')
        except Exception:
            error_info = StackTraceCapture.capture_exception()
            if txn and error_info:
                txn.record_error(error_info)
            self.end_transaction(txn, result='failure')
            raise
    
    @contextmanager
    def span(self, name, span_type, subtype=None, action=None):
        txn = self._current_transaction
        if not txn:
            yield None
            return
        
        span_obj = txn.begin_span(name, span_type, subtype, action)
        
        if self._elastic_client:
            try:
                import elasticapm
                with elasticapm.capture_span(name, span_type=span_type, leaf=True):
                    try:
                        yield span_obj
                    except Exception:
                        span_obj.outcome = 'failure'
                        raise
                    finally:
                        txn.end_span(span_obj)
                return
            except Exception:
                pass
        
        try:
            yield span_obj
        except Exception:
            span_obj.outcome = 'failure'
            raise
        finally:
            txn.end_span(span_obj)
    
    def capture_error(self, exception=None, message=None):
        if not self.config.enabled:
            return
        
        self._metrics['error_count'] += 1
        
        if exception:
            error_info = {
                'exception_type': type(exception).__name__,
                'exception_message': str(exception),
                'stack_trace': StackTraceCapture.capture(),
                'timestamp': datetime.utcnow().isoformat()
            }
        else:
            error_info = StackTraceCapture.capture_exception()
            if not error_info:
                error_info = {
                    'message': message or 'Unknown error',
                    'stack_trace': StackTraceCapture.capture(),
                    'timestamp': datetime.utcnow().isoformat()
                }
            else:
                error_info['timestamp'] = datetime.utcnow().isoformat()
        
        if self._current_transaction:
            self._current_transaction.record_error(error_info)
        
        if self._elastic_client:
            try:
                if exception:
                    self._elastic_client.capture_exception()
                else:
                    self._elastic_client.capture_message(message or 'Error captured')
            except Exception as e:
                logger.debug(f"Elastic APM capture_error: {e}")
        
        logger.error(f"Error captured: {json.dumps(error_info, indent=2, default=str)}")
        return error_info
    
    def _report_transaction(self, transaction):
        txn_data = transaction.to_dict()
        logger.info(
            f"\n{'='*60}\n"
            f"TRANSACTION REPORT\n"
            f"{'='*60}\n"
            f"Name: {txn_data['name']}\n"
            f"Type: {txn_data['type']}\n"
            f"Duration: {txn_data['duration_ms']:.2f}ms\n"
            f"Result: {txn_data['result']}\n"
            f"Outcome: {txn_data['outcome']}\n"
            f"Spans: {txn_data['span_count']}\n"
            f"Errors: {len(txn_data['errors'])}\n"
            f"{'='*60}"
        )
        
        if txn_data['context'].get('request', {}).get('method'):
            req = txn_data['context']['request']
            logger.info(
                f"Request: {req.get('method')} {req.get('url')}\n"
                f"Request Headers: {json.dumps(req.get('headers', {}), default=str)}\n"
                f"Request Body: {req.get('body')}"
            )
        
        if txn_data['context'].get('response', {}).get('status_code'):
            resp = txn_data['context']['response']
            logger.info(
                f"Response: {resp.get('status_code')}\n"
                f"Response Headers: {json.dumps(resp.get('headers', {}), default=str)}\n"
                f"Response Body: {resp.get('body')}"
            )
        
        for span_data in txn_data['spans']:
            logger.info(
                f"  Span: {span_data['name']} "
                f"(type: {span_data['type']}, "
                f"duration: {span_data['duration_ms']:.2f}ms, "
                f"outcome: {span_data['outcome']})"
            )
            if span_data.get('context', {}).get('sql'):
                logger.info(f"    SQL: {span_data['context']['sql']}")
        
        for error in txn_data['errors']:
            logger.error(f"  Error: {error.get('exception_type', 'Unknown')}: {error.get('exception_message', error.get('message', ''))}")
    
    def get_metrics(self):
        avg_duration = 0
        if self._metrics['transaction_count'] > 0:
            avg_duration = self._metrics['total_duration_ms'] / self._metrics['transaction_count']
        
        return {
            **self._metrics,
            'avg_transaction_duration_ms': avg_duration,
            'service_name': self.config.service_name,
            'environment': self.config.environment
        }
    
    def get_recent_transactions(self, limit=10):
        return [t.to_dict() for t in self._transactions[-limit:]]
    
    def close(self):
        if self._elastic_client:
            try:
                self._elastic_client.close()
            except Exception:
                pass
        logger.info(f"APM Client closed. Final metrics: {json.dumps(self.get_metrics(), default=str)}")


