# Instrumentation Decorators
# ============================================================

def trace_function(name=None, transaction_type='custom'):
    """Decorator to trace a function as a transaction."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            apm = APMClient()
            txn_name = name or f"{func.__module__}.{func.__qualname__}"
            with apm.transaction(txn_name, transaction_type) as txn:
                if txn:
                    txn.set_custom_context('function', func.__qualname__)
                    txn.set_custom_context('args_count', len(args))
                    txn.set_custom_context('kwargs_keys', list(kwargs.keys()))
                result = func(*args, **kwargs)
                return result
        return wrapper
    return decorator


def trace_span(name=None, span_type='code', subtype=None):
    """Decorator to trace a function as a span within current transaction."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            apm = APMClient()
            span_name = name or f"{func.__qualname__}"
            with apm.span(span_name, span_type, subtype) as span_obj:
                result = func(*args, **kwargs)
                return result
        return wrapper
    return decorator


