class InstrumentedDatabase:
    """SQLite database wrapper with APM instrumentation."""
    
    def __init__(self, db_path=':memory:'):
        self.db_path = db_path
        self.connection = sqlite3.connect(db_path)
        self.connection.row_factory = sqlite3.Row
        self.apm = APMClient()
        logger.info(f"Database connected: {db_path}")
    
    def execute(self, query, params=None):
        with self.apm.span(
            self._get_query_name(query),
            span_type='db',
            subtype='sqlite',
            action='query'
        ) as span:
            if span and self.apm.config.collect_sql_queries:
                span.set_context('sql', {
                    'query': query,
                    'params': str(params) if params else None,
                    'database': self.db_path
                })
            
            try:
                cursor = self.connection.cursor()
                if params:
                    result = cursor.execute(query, params)
                else:
                    result = cursor.execute(query)
                self.connection.commit()
                
                if span:
                    span.set_context('rows_affected', cursor.rowcount)
                
                return result
            except Exception as e:
                self.apm.capture_error(e)
                raise
    
    def fetchall(self, query, params=None):
        with self.apm.span(
            self._get_query_name(query),
            span_type='db',
            subtype='sqlite',
            action='query'
        ) as span:
            if span and self.apm.config.collect_sql_queries:
                span.set_context('sql', {
                    'query': query,
                    'params': str(params) if params else None,
                    'database': self.db_path
                })
            
            try:
                cursor = self.connection.cursor()
                if params:
                    cursor.execute(query, params)
                else:
                    cursor.execute(query)
                
                rows = cursor.fetchall()
                
                if span:
                    span.set_context('rows_returned', len(rows))
                
                return [dict(row) for row in rows]
            except Exception as e:
                self.apm.capture_error(e)
                raise
    
    def fetchone(self, query, params=None):
        with self.apm.span(
            self._get_query_name(query),
            span_type='db',
            subtype='sqlite',
            action='query'
        ) as span:
            if span and self.apm.config.collect_sql_queries:
                span.set_context('sql', {
                    'query': query,
                    'params': str(params) if params else None,
                    'database': self.db_path
                })
            
            try:
                cursor = self.connection.cursor()
                if params:
                    cursor.execute(query, params)
                else:
                    cursor.execute(query)
                
                row = cursor.fetchone()
                return dict(row) if row else None
            except Exception as e:
                self.apm.capture_error(e)
                raise
    
    def _get_query_name(self, query):
        parts = query.strip().split()
        if len(parts) >= 2:
            operation = parts[0].upper()
            # For INSERT INTO, CREATE TABLE, etc.
            if operation in ('INSERT', 'CREATE', 'DROP', 'ALTER'):
                table = parts[2] if len(parts) > 2 else 'unknown'
            elif operation in ('SELECT', 'DELETE'):
                # Find FROM clause
                upper_parts = [p.upper() for p in parts]
                if 'FROM' in upper_parts:
                    idx = upper_parts.index('FROM')
                    table = parts[idx + 1] if idx + 1 < len(parts) else 'unknown'
                else:
                    table = 'unknown'
            elif operation == 'UPDATE':
                table = parts[1] if len(parts) > 1 else 'unknown'
            else:
                table = 'unknown'
            return f"{operation} {table}"
        return "SQL Query"
    
    def close(self):
        self.connection.close()
        logger.info(f"Database disconnected: {self.db_path}")


