class UserService:
    """Sample service demonstrating APM instrumentation."""
    
    def __init__(self):
        self.apm = APMClient()
        self.db = InstrumentedDatabase(':memory:')
        self.http_client = InstrumentedHTTPClient()
        self._initialize_db()
    
    def _initialize_db(self):
        with self.apm.transaction('db_initialization', 'setup') as txn:
            self.db.execute('''
                CREATE TABLE IF NOT EXISTS users (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    name TEXT NOT NULL,
                    email TEXT UNIQUE NOT NULL,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            ''')
            self.db.execute('''
                CREATE TABLE IF NOT EXISTS user_sessions (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    session_token TEXT NOT NULL,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (user_id) REFERENCES users(id)
                )
            ''')
            if txn:
                txn.set_custom_context('tables_created', ['users', 'user_sessions'])
    
    @trace_function(name='UserService.create_user', transaction_type='request')
    def create_user(self, name, email):
        """Create a new user with full request/response tracking."""
        apm = APMClient()
        txn = apm._current_transaction
        
        if txn:
            txn.set_request_context(
                method='POST',
                url='/api/users',
                headers={'Content-Type': 'application/json', 'Authorization': 'Bearer ***'},
                body=json.dumps({'name': name, 'email': email})
            )
        
        # Validate input
        with apm.span('validate_input', 'code', 'validation'):
            if not name or not email:
                raise ValueError("Name and email are required")
            if '@' not in email:
                raise ValueError("Invalid email format")
        
        # Insert into database
        self.db.execute(
            'INSERT INTO users (name, email) VALUES (?, ?)',
            (name, email)
        )
        
        # Fetch the created user
        user = self.db.fetchone(
            'SELECT * FROM users WHERE email = ?',
            (email,)
        )
        
        # Simulate external API call (e.g., sending welcome email)
        with apm.span('send_welcome_email', 'external', 'http'):
            self.http_client.post(
                'https://api.email-service.com/send',
                body=json.dumps({
                    'to': email,
                    'template': 'welcome',
                    'name': name
                })
            )
        
        if txn:
            txn.set_response_context(
                status_code=201,
                headers={'Content-Type': 'application/json'},
                body=json.dumps(user, default=str)
            )
            txn.set_tag('user_email', email)
        
        return user
    
    @trace_function(name='UserService.get_user', transaction_type='request')
    def get_user(self, user_id):
        """Get a user by ID."""
        apm = APMClient()
        txn = apm._current_transaction
        
        if txn:
            txn.set_request_context(
                method='GET',
                url=f'/api/users/{user_id}',
                headers={'Accept': 'application/json'}
            )
        
        user = self.db.fetchone(
            'SELECT * FROM users WHERE id = ?',
            (user_id,)
        )
        
        if not user:
            if txn:
                txn.set_response_context(status_code=404, body='{"error": "User not found"}')
            return None
        
        if txn:
            txn.set_response_context(
                status_code=200,
                headers={'Content-Type': 'application/json'},
                body=json.dumps(user, default=str)
            )
        
        return user
    
    @trace_function(name='UserService.list_users', transaction_type='request')
    def list_users(self):
        """List all users."""
        apm = APMClient()
        txn = apm._current_transaction
        
        if txn:
            txn.set_request_context(
                method='GET',
                url='/api/users',
                headers={'Accept': 'application/json'}
            )
        
        users = self.db.fetchall('SELECT * FROM users ORDER BY created_at DESC')
        
        if txn:
            txn.set_response_context(
                status_code=200,
                headers={'Content-Type': 'application/json', 'X-Total-Count': str(len(users))},
                body=json.dumps(users, default=str)
            )
            txn.set_custom_context('user_count', len(users))
        
        return users
    
    @trace_function(name='UserService.complex_operation', transaction_type='background')
    def complex_operation(self):
        """Demonstrates nested spans and error handling."""
        apm = APMClient()
        
        # Step 1: Data processing
        with apm.span('data_processing', 'code', 'processing') as span:
            time.sleep(0.02)  # Simulate processing
            processed_items = 42
            if span:
                span.set_context('items_processed', processed_items)
        
        # Step 2: External API calls
        with apm.span('external_api_calls', 'external', 'http'):
            self.http_client.get('https://api.service-a.com/data')
            self.http_client.get('https://api.service-b.com/data')
        
        # Step 3: Database operations
        with apm.span('batch_db_operations', 'db', 'sqlite', 'batch'):
            users = self.db.fetchall('SELECT * FROM users')
            for user in users:
                self.db.fetchone(
                    'SELECT COUNT(*) as session_count FROM user_sessions WHERE user_id = ?',
                    (user['id'],)
                )
        
        return {'processed_items': processed_items, 'users_checked': len(users) if users else 0}
    
    @trace_function(name='UserService.failing_operation', transaction_type='request')
    def failing_operation(self):
        """Demonstrates error capture with full stack traces."""
        apm = APMClient()
        txn = apm._current_transaction
        
        if txn:
            txn.set_request_context(
                method='POST',
                url='/api/danger',
                headers={'Content-Type': 'application/json'}
            )
        
        with apm.span('risky_database_query', 'db', 'sqlite'):
            # This will fail - table doesn't exist
            self.db.fetchall('SELECT * FROM nonexistent_table')
    
    def close(self):
        self.db.close()


# ============================================================
# Flask Integration Example (if Flask is available)
# ============================================================

def create_flask_app():
    """Create a Flask app with APM middleware."""
    try:
        from flask import Flask, request, jsonify
    except ImportError:
        logger.info("Flask not installed. Skipping Flask integration example.")
        return None
    
    app = Flask(__name__)
    apm = APMClient()
    
    # Try to use elastic-apm Flask integration
    try:
        from elasticapm.contrib.flask import ElasticAPM
        elastic_apm = ElasticAPM(
            app,
            service_name=apm.config.service_name,
            server_url=apm.config.server_url,
            secret_token=apm.config.secret_token,
            environment=apm.config.environment,
            capture_body=apm.config.capture_body,
            capture_headers=apm.config.capture_headers,
        )
        logger.info("Elastic APM Flask integration enabled")
    except ImportError:
        logger.info("Using custom APM middleware for Flask")
        
        @app.before_request
        def before_request():
            txn = apm.begin_transaction(
                f"{request.method} {request.path}",
                'request'
            )
            if txn:
                txn.set_request_context(
                    method=request.method,
                    url=request.url,
                    headers=dict(request.headers),
                    body=request.get_data(as_text=True)
                )
            request._apm_transaction = txn
        
        @app.after_request
        def after_request(response):
            txn = getattr(request, '_apm_transaction', None)
            if txn:
                txn.set_response_context(
                    status_code=response.status_code,
                    headers=dict(response.headers),
                    body=response.get_data(as_text=True)
                )
                result = f"HTTP {response.status_code}"
                apm.end_transaction(txn, result)
            return response
        
        @app.errorhandler(Exception)
        def handle_error(e):
            apm.capture_error(e)
            return jsonify({'error': str(e)}), 500
    
    # Define routes
    service = UserService()
    
    @app.route('/api/users', methods=['GET'])
    def list_users():
        users = service.list_users()
        return jsonify(users)
    
    @app.route('/api/users', methods=['POST'])
    def create_user():
        data = request.get_json()
        user = service.create_user(data['name'], data['email'])
        return jsonify(user), 201
    
    @app.route('/api/users/<int:user_id>', methods=['GET'])
    def get_user(user_id):
        user = service.get_user(user_id)
        if user:
            return jsonify(user)
        return jsonify({'error': 'Not found'}), 404
    
    @app.route('/api/metrics', methods=['GET'])
    def get_metrics():
        return jsonify(apm.get_metrics())
    
    return app


