# Main Execution
# ============================================================

def main():
    """Run the instrumented application demonstration."""
    
    print("\n" + "=" * 70)
    print("APM Instrumented Application Demo")
    print("=" * 70)
    
    # Initialize APM
    config = APMConfig()
    apm = APMClient(config)
    
    # Initialize service
    service = UserService()
    
    # --- Demo 1: Create Users ---
    print("\n--- Demo 1: Creating Users ---")
    try:
        user1 = service.create_user("Alice Johnson", "alice@example.com")
        print(f"Created user: {user1}")
        
        user2 = service.create_user("Bob Smith", "bob@example.com")
        print(f"Created user: {user2}")
        
        user3 = service.create_user("Charlie Brown", "charlie@example.com")
        print(f"Created user: {user3}")
    except Exception as e:
        print(f"Error: {e}")
    
    # --- Demo 2: Get User ---
    print("\n--- Demo 2: Getting User ---")
    user = service.get_user(1)
    print(f"Retrieved user: {user}")
    
    # --- Demo 3: List Users ---
    print("\n--- Demo 3: Listing Users ---")
    users = service.list_users()
    print(f"Total users: {len(users)}")
    for u in users:
        print(f"  - {u}")
    
    # --- Demo 4: Complex Operation ---
    print("\n--- Demo 4: Complex Operation with Nested Spans ---")
    result = service.complex_operation()
    print(f"Complex operation result: {result}")
    
    # --- Demo 5: Error Handling ---
    print("\n--- Demo 5: Error Handling and Capture ---")
    try:
        service.failing_operation()
    except Exception as e:
        print(f"Expected error caught: {e}")
    
    # --- Demo 6: Manual Transaction ---
    print("\n--- Demo 6: Manual Transaction with Custom Context ---")
    with apm.transaction('manual_batch_job', 'background') as txn:
        if txn:
            txn.set_custom_context('batch_id', 'BATCH-001')
            txn.set_custom_context('source', 'cron_job')
            txn.set_tag('priority', 'high')
        
        with apm.span('step_1_fetch_data', 'code'):
            time.sleep(0.01)
        
        with apm.span('step_2_transform', 'code'):
            time.sleep(0.015)
        
        with apm.span('step_3_store_results', 'db', 'sqlite'):
            time.sleep(0.01)
    
    # --- Demo 7: Validation Error ---
    print("\n--- Demo 7: Input Validation Error ---")
    try:
        service.create_user("", "invalid")
    except ValueError as e:
        print(f"Validation error caught: {e}")
    
    # --- Demo 8: Duplicate User Error ---
    print("\n--- Demo 8: Duplicate User Error ---")
    try:
        service.create_user("Alice Duplicate", "alice@example.com")
    except Exception as e:
        print(f"Duplicate error caught: {e}")
    
    # --- Print Final Metrics ---
    print("\n" + "=" * 70)
    print("FINAL APM METRICS")
    print("=" * 70)
    metrics = apm.get_metrics()
    for key, value in metrics.items():
        if isinstance(value, float):
            print(f"  {key}: {value:.2f}")
        else:
            print(f"  {key}: {value}")
    
    # --- Print Recent Transactions Summary ---
    print("\n" + "=" * 70)
    print("RECENT TRANSACTIONS SUMMARY")
    print("=" * 70)
    for txn_data in apm.get_recent_transactions():
        duration = txn_data.get('duration_ms', 0) or 0
        print(
            f"  [{txn_data['outcome'].upper():7s}] "
            f"{txn_data['name']:45s} "
            f"{duration:8.2f}ms "
            f"({txn_data['span_count']} spans, {len(txn_data['errors'])} errors)"
        )
    
    # --- Try Flask App ---
    print("\n" + "=" * 70)
    print("FLASK APPLICATION")
    print("=" * 70)
    flask_app = create_flask_app()
    if flask_app:
        print("Flask app created. Run with: flask_app.run(debug=True, port=5000)")
        print("Endpoints:")
        print("  GET  /api/users          - List users")
        print("  POST /api/users          - Create user")
        print("  GET  /api/users/<id>     - Get user")
        print("  GET  /api/metrics        - APM metrics")
        # Uncomment to run: flask_app.run(debug=True, port=5000)
    else:
        print("Flask not available. Install with: pip install flask")
    
    # Cleanup
    service.close()
    apm.close()
    
    # Reset singleton for clean testing
    APMClient._instance = None


if __name__ == '__main__':
    main()